from a2a.types import AgentCapabilities, AgentCard, AgentSkillskill = AgentSkill(id='weather',                   name='Returns weather information',                   description='Fetch the real-time weather prediction information of a location',                   tags=['weather', 'sunny', 'rainy', 'prediction'],                   examples=['Is it sunny?', 'What is the weather today?'],                   inputModes=['text/plain'],                   outputModes=['text/plain'])agent_port = 9999public_agent_card = AgentCard(name='Weather Agent',                              description='A weather agent',                              url=f'http://localhost:{agent_port}/',                              version='1.0.0',                              default_input_modes=['text'],                              default_output_modes=['text'],                              capabilities=AgentCapabilities(streaming=True),                              skills=[skill])from a2a.server.apps import A2AStarletteApplicationfrom a2a.server.request_handlers import DefaultRequestHandlerfrom a2a.server.tasks import InMemoryTaskStorefrom a2a_agent_executor_weather import WeatherAgentExecutorrequest_handler = DefaultRequestHandler(agent_executor=WeatherAgentExecutor(),                                        task_store=InMemoryTaskStore())server = A2AStarletteApplication(agent_card=public_agent_card,                                 http_handler=request_handler)import uvicornuvicorn.run(server.build(),             host='0.0.0.0',             port=agent_port)